14	using DiagCode = slang::DiagCode;
15	using DiagGroup = slang::DiagGroup;
16	using DiagSubsystem = slang::DiagSubsystem;
17	using Diagnostic = slang::Diagnostic;
18	using Diagnostics = slang::Diagnostics;
19	using DiagnosticEngine = slang::DiagnosticEngine;
20	using DiagnosticSeverity = slang::DiagnosticSeverity;
21	using SourceRange = slang::SourceRange;
22	using SourceLocation = slang::SourceLocation;
23	
24	Diagnostic &DiagnosticIssuer::add_diag(DiagCode code, SourceLocation location)
25	{
26		issued_diagnostics.emplace_back(code, location);
27		return issued_diagnostics.back();
28	}
29	
30	Diagnostic &DiagnosticIssuer::add_diag(DiagCode code, SourceRange sourceRange)
31	{
32		Diagnostic &diag = add_diag(code, sourceRange.start());
33		diag << sourceRange;
34		return diag;
35	}
36	
37	void DiagnosticIssuer::add_diag(Diagnostic diag)
38	{
39		issued_diagnostics.push_back(diag);
40	}
41	
42	void DiagnosticIssuer::add_diagnostics(const Diagnostics &diagnostics)
43	{
44		for (const Diagnostic &diag : diagnostics)
45			add_diag(diag);
46	}
47	
48	void DiagnosticIssuer::report_into(DiagnosticEngine &engine)
49	{
50		for (auto &diag : issued_diagnostics)
51			engine.issue(diag);
52	}
