140	DiagGroup unsynthesizable("unsynthesizable",
141			{IffUnsupported, GenericTimingUnsyn, BothEdgesUnsupported, ExpectingIfElseAload,
142					IfElseAloadPolarity, IfElseAloadMismatch, UnsynthesizableFeature});
143	DiagGroup sanity("sanity", {EdgeImplicitMixing});
144	
145	void setup_messages(slang::DiagnosticEngine &engine)
146	{
147		// clang-format off
148		engine.setMessage(IffUnsupported, "iff qualifier not supported in combination with this event");
149		engine.setMessage(SignalSensitivityAmbiguous, "non-edge sensitivity on a signal will be synthesized as @* sensitivity");
150		engine.setSeverity(SignalSensitivityAmbiguous, DiagnosticSeverity::Warning);
151		engine.setMessage(EdgeImplicitMixing, "mixing of implicit and edge sensitivity");
152		engine.setMessage(GenericTimingUnsyn, "unsynthesizable timing control (ignore with '--ignore-timing')");
153		engine.setMessage(BothEdgesUnsupported, "@(edge) will not be synthesized (override with '--allow-dual-edge-ff')");
154		engine.setMessage(WaitStatementUnsupported, "wait statement will not be synthesized");
155		engine.setSeverity(WaitStatementUnsupported, DiagnosticSeverity::Warning);
156		engine.setMessage(NoteSignalEvent, "signal event specified here");
157		engine.setSeverity(NoteSignalEvent, DiagnosticSeverity::Note);
158	
159		engine.setMessage(ExpectingIfElseAload, "simple if-else pattern expected in modeling an asynchronous load on a flip-flop");
160		engine.setMessage(NoteDuplicateEdgeSense, "asynchronous load pattern implied by edge sensitivity on multiple signals");
161		engine.setSeverity(NoteDuplicateEdgeSense, DiagnosticSeverity::Note);
162	
163		engine.setMessage(IfElseAloadPolarity, "polarity of condition doesn't match edge sensitivity");
164		engine.setMessage(IfElseAloadMismatch, "condition cannot be matched to any signal from the event list");
165	
166		engine.setMessage(LatchNotInferred, "latch not inferred for variable '{}' driven from always_latch procedure");
167		engine.setSeverity(LatchNotInferred, DiagnosticSeverity::Warning);
168	
169		engine.setMessage(MissingAload, "asynchronous load value missing for variable '{}'");
170		engine.setSeverity(MissingAload, DiagnosticSeverity::Warning);
171		engine.setMessage(NoteProcessDriver, "variable driven from this procedure");
172		engine.setSeverity(NoteProcessDriver, DiagnosticSeverity::Note);
173	
174		engine.setMessage(AlwaysFFBadTiming, "timing control does not model a flip-flop");
175		engine.setSeverity(AlwaysFFBadTiming, DiagnosticSeverity::Error);
176	
177		engine.setMessage(MissingStopCondition, "stop condition is missing; loop cannot be unrolled");
178		engine.setSeverity(MissingStopCondition, DiagnosticSeverity::Error);
179	
180		engine.setMessage(BadMemoryExpr, "unsupported operation on a memory variable");
181		engine.setSeverity(BadMemoryExpr, DiagnosticSeverity::Error);
182	
183		engine.setMessage(MemoryNotInferred, "cannot infer memory from a variable despite '{}' attribute");
184		engine.setSeverity(MemoryNotInferred, DiagnosticSeverity::Error);
185		engine.setMessage(NoteUsageBlame, "inference prevented by variable usage here");
186		engine.setSeverity(NoteUsageBlame, DiagnosticSeverity::Note);
187	
188		for (auto code : unsynthesizable.getDiags())
189			engine.setSeverity(code, DiagnosticSeverity::Error);
190		for (auto code : sanity.getDiags())
191			engine.setSeverity(code, DiagnosticSeverity::Error);
192	
193		engine.setMessage(UnrollLimitExhausted, "unroll limit of {} exhausted [--unroll-limit=]");
194		engine.setSeverity(UnrollLimitExhausted, DiagnosticSeverity::Error);
195	
196		engine.setMessage(NoteLoopContributes, "loop contributes to unroll tally");
197		engine.setSeverity(NoteLoopContributes, DiagnosticSeverity::Note);
198	
199		engine.setMessage(NonconstWildcardEq, "wildcard equality unsynthesizable with non-constant right-hand operand");
200		engine.setSeverity(NonconstWildcardEq, DiagnosticSeverity::Error);
201	
202		engine.setMessage(AssertionUnsupported, "unsupported assertion statement");
203		engine.setSeverity(AssertionUnsupported, DiagnosticSeverity::Error);
204	
205		engine.setMessage(LangFeatureUnsupported, "unsupported language feature");
206		engine.setSeverity(LangFeatureUnsupported, DiagnosticSeverity::Error);
207	
208		engine.setMessage(UnsupportedLhs, "unsupported assignment target expression");
209		engine.setSeverity(UnsupportedLhs, DiagnosticSeverity::Error);
210	
211		engine.setMessage(ArgumentTypeUnsupported, "unsupported argument type: {}");
212		engine.setSeverity(ArgumentTypeUnsupported, DiagnosticSeverity::Error);
213	
214		engine.setMessage(MultiportUnsupported, "multiports unsupported on kept module boundary");
215		engine.setSeverity(MultiportUnsupported, DiagnosticSeverity::Error);
216	
217		engine.setMessage(UnsupportedBlackboxConnection, "{} port on blackbox instance unsupported");
218		engine.setSeverity(UnsupportedBlackboxConnection, DiagnosticSeverity::Error);
219	
220		engine.setMessage(UnsupportedPortDirection, "port direction '{}' on kept module boundary unsupported");
221		engine.setSeverity(UnsupportedPortDirection, DiagnosticSeverity::Error);
222	
223		engine.setMessage(ModportRequired, "interface port on kept module boundary must be a modport");
224		engine.setSeverity(ModportRequired, DiagnosticSeverity::Error);
225	
226		engine.setMessage(FixedSizeRequired, "expression of type {} with dynamic size unsupported for synthesis");
227		engine.setSeverity(FixedSizeRequired, DiagnosticSeverity::Error);
228	
229		engine.setMessage(AloadOne, "multiple asynchronous loads unsupported");
230		engine.setSeverity(AloadOne, DiagnosticSeverity::Error);
231	
232		engine.setMessage(BadInlinedPortConnection, "direction '{}' on inlined port connection unsupported");
233		engine.setSeverity(BadInlinedPortConnection, DiagnosticSeverity::Error);
234	
235		engine.setMessage(NoParamsOnUnkBboxes, "parameters on unknown blackboxes unsupported");
236		engine.setSeverity(NoParamsOnUnkBboxes, DiagnosticSeverity::Error);
237	
238		engine.setMessage(BboxTypeParameter, "blackbox cannot have a type parameter");
239		engine.setSeverity(BboxTypeParameter, DiagnosticSeverity::Error);
240	
241		engine.setMessage(BboxExportPortWidths, "cannot export a blackbox definition with non-constant port widths");
242		engine.setSeverity(BboxExportPortWidths, DiagnosticSeverity::Error);
243	
244		engine.setMessage(NoteIgnoreInitial, "use option '--ignore-initial' to ignore initial procedures");
245		engine.setSeverity(NoteIgnoreInitial, DiagnosticSeverity::Note);
246	
247		engine.setMessage(PortCorrespondence, "ports without direct correspondence to an internal net/variable unsupported");
248		engine.setSeverity(PortCorrespondence, DiagnosticSeverity::Error);
249	
250		engine.setMessage(UnsynthesizableFeature, "unsynthesizable feature");
251	
252		engine.setMessage(SVAUnsupported, "SVA unsupported (ignore all assertions with '--ignore-assertions')");
253		engine.setSeverity(SVAUnsupported, DiagnosticSeverity::Error);
254	
255		engine.setMessage(ExpectStatementUnsupported, "expect statement will not be synthesized");
256		engine.setSeverity(ExpectStatementUnsupported, DiagnosticSeverity::Warning);
257	
258		engine.setMessage(ProgramUnsupported, "program block will not be synthesized");
259		engine.setSeverity(ProgramUnsupported, DiagnosticSeverity::Warning);
260	
261		engine.setMessage(ForbiddenDemotion, "disabling error '{}' is unsupported with sv-elab");
262		engine.setSeverity(ForbiddenDemotion, DiagnosticSeverity::Error);
263	
264		engine.setMessage(UdpUnsupported, "user-defined primitives unsupported, set '--udp-handling=blackboxes' option to treat it as blackboxes");
265		engine.setSeverity(UdpUnsupported, DiagnosticSeverity::Error);
266	
267		engine.setMessage(PrimTypeUnsupported, "primitives of type '{}' unsupported");
268		engine.setSeverity(PrimTypeUnsupported, DiagnosticSeverity::Error);
269	
270		engine.setMessage(ReferenceAcrossKeptHierBoundary, "hierarchical reference across preserved module boundary");
271		engine.setSeverity(ReferenceAcrossKeptHierBoundary, DiagnosticSeverity::Error);
272		engine.setMessage(NoteModuleBlackboxBecauseAttribute, "module '{}' is a blackbox because of attribute");
273		engine.setSeverity(NoteModuleBlackboxBecauseAttribute, DiagnosticSeverity::Note);
